import{_ as a,o as e,c as t,a2 as o}from"./chunks/framework.4hJCcvDE.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/知识点_003-iOS可执行文件结构.md","filePath":"blog/知识点_003-iOS可执行文件结构.md","lastUpdated":1784835052000}'),l={name:"blog/知识点_003-iOS可执行文件结构.md"};function i(r,_,s,c,p,n){return e(),t("div",null,[..._[0]||(_[0]=[o('<p>过苹果审核的时候每次都被扫到关键词,需要把最终文件里的关键词干掉,研究了一下iOS的那个安装包。 其中的文本这些没什么好讲的,主要麻烦的是这个编译生成的可执行文件,搜了一下没搜到相关的介绍,可能是我关键词不对吧。 只能自己搞了研究一下。</p><p>初步看了下文件,里面的明文字符主要是这些东西</p><ol><li>OC的类和接口名称,以及写在代码里的字符串常量。这个没什么好说的。</li><li>c++的字符串常量。我们这个游戏是c++lua的模式,大头主要就是各种错误日志以及导出到lua的接口</li><li>.c文件的绝对路径。这个比较奇怪,为什么会把路径也放进来,而且是.c。</li></ol><p>主要就是这三类,其他的还有一些导入的系统库名称之类的,苹果应该不会去查也就没研究了。 上面三类的的话，第一类和第二类都好理解，也有办法做混淆，虽然导出到lua的接口混淆难度比较大。 现在主要在研究第三类，没搞懂它是做什么用的，暂时也没找到办法给他去掉。 后续研究了一下,发现是由于iOS sdk中的assert实现使用了__FILE__关键字的原因,这个关键字作用是在预编译时将自己替换成文件的绝对路径。 后面我们把代码中的__FILE__关键字都替换掉了,mm文件中使用assert关键字的地方也换成了别的。这样以后可执行文件中就不再出现计算机上的绝对路径了。</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><blockquote><p>未完待续</p></blockquote>',6)])])}const u=a(l,[["render",i]]);export{m as __pageData,u as default};
